sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;

    c.getStatusClass = function(status) {
        switch(status) {
            case 'confirmed': return 'label-success';
            case 'cancelled': return 'label-default';
            case 'attended': return 'label-info';
            default: return 'label-warning';
        }
    };
};

sp_widget.css:
.sp-card {
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-large;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    background: $background-primary;
    overflow: hidden;
    margin-bottom: 24px;
}
.sp-card-body-flush {
    padding: 0;
    overflow: hidden;
}
.sp-th {
    font-size: 12px;
    font-weight: 600;
    color: $text-muted;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    padding: 12px 16px;
    border-bottom: 2px solid $border-tertiary;
    background: $background-secondary;
}
.sp-td {
    font-size: $font-size-small;
    padding: 12px 16px;
    color: $text-color;
    border-bottom: 1px solid $border-tertiary;
    vertical-align: middle;
}
.sp-btn-icon {
    width: 30px;
    height: 30px;
    border-radius: $border-radius-base;
    border: 1px solid $border-tertiary;
    background: transparent;
    color: $text-muted;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    &:hover {
        background: $background-secondary;
        color: $brand-primary;
    }
}
.sp-btn-primary {
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    font-weight: 500;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s, box-shadow 0.15s;
    cursor: pointer;
    border: none;
    background: $brand-primary;
    color: $btn-primary-color;
    &:hover:not(:disabled) {
        background: $brand-primary-dark;
        box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
        color: $btn-primary-color;
    }
}
.sp-empty-state {
    padding: 64px 24px;
}
.sp-empty-icon {
    font-size: 48px;
    margin-bottom: 16px;
    display: block;
    opacity: 0.35;
    color: $text-muted;
}
.sp-empty-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin-bottom: 8px;
}

sp_widget.script:
(function() {
    data.registrations = [];
    data.message = '';

    try {
        var gr = new GlideRecord('x_2097092_linq_registration');
        gr.addQuery('student', gs.getUserID());
        gr.orderByDesc('registration_date');
        gr.setLimit(50);
        gr.query();

        while (gr.next()) {
            var eventGr = new GlideRecord('x_2097092_linq_event');
            var eventTitle = '';
            var eventDate = '';
            if (eventGr.get(gr.getValue('event'))) {
                eventTitle = eventGr.getValue('title') + '';
                eventDate = eventGr.getDisplayValue('event_date') + '';
            }

            data.registrations.push({
                sys_id: gr.getUniqueValue(),
                event_title: eventTitle,
                event_date: eventDate,
                status: gr.getValue('status') + '',
                qr_token: gr.getValue('qr_token') + ''
            });
        }
    } catch (e) {
        gs.error('linq-my-regs error: ' + e.message);
        data.message = 'An error occurred loading registrations.';
    }
})();
